scwin.f_chkResultsConfirmationCommodity = function (row) {

    if (row > 0) {
        if (!$c.gus.cfIsNull(ds_odrCommWrkPath.getCellData(row, "wrkRsltsNo").trim())) {
            return true;	// 실적이 존재하는 경우
        }
