                ds_odrWrkPathStepDetail.setCellData(ds_odrWrkPathStepDetail.getRowPosition(), "dptWrkPlNmOrg", ds_order.getCellData(ds_order.getRowPosition(), "dtpWrkPlNm"))	// 출발작업장명
